{
  "title": "संदर्भ विंडो की मूल बातें",
  "group": "मूलभूत",
  "options": [
    {
      "text": "प्रति मिनट अनुरोधों की अधिकतम संख्या"
    },
    {
      "text": "इनपुट और आउटपुट के लिए संयुक्त टोकन सीमा"
    },
    {
      "text": "एक वार्तालाप में संदेशों की संख्या"
    },
    {
      "text": "सत्रों के बीच उपलब्ध मेमोरी"
    }
  ],
  "questionProse": [
    "LLM में \"संदर्भ विंडो\" किसे संदर्भित करता है?"
  ],
  "explanationProse": [
    "संदर्भ विंडो एक एकल कॉल में मॉडल द्वारा प्रोसेस किए जा सकने वाले टोकनों की कुल संख्या है — **इनपुट + आउटपुट संयुक्त**। 128K संदर्भ विंडो का मतलब है कि आपका प्रॉम्प्ट + पुनर्प्राप्त दस्तावेज़ + वार्तालाप इतिहास + मॉडल का उत्तर सभी 128,000 टोकनों के भीतर फिट होने चाहिए।\n\n    इसका सत्रों, मेमोरी या दर सीमाओं से कोई लेना-देना नहीं है। जब आप सीमा तक पहुँचते हैं, तो मॉडल या तो छोटा करता है, त्रुटि देता है, या — इससे भी बुरा — चुपचाप उन टोकनों को गिरा देता है जिनकी आपने उम्मीद नहीं की थी।"
  ]
}
